	   )

mapper.delete:
/* mapper.login.com.erns.coching.BlacklistTokenDAO.delete */

DELETE FROM T_TOKEN_BLACKLIST

	AND TOKEN = #{value, jdbcType=VARCHAR}

/* mapper.login.com.erns.coching.BlacklistTokenDAO.deleteExpiredTokens */

