mapper.insert:
/* com.erns.coching.login.mapper.BlacklistTokenDAO.insertFromAccess */

DELETE FROM T_TOKEN_BLACKLIST WHERE TOKEN = #{value	, jdbcType=VARCHAR};


INSERT INTO T_TOKEN_BLACKLIST (
	TOKEN, SITE_TYPE, MEMB_SEQ, EXP_DATE, RGT_DTTM
)
SELECT
	TOKEN, SITE_TYPE, MEMB_SEQ, EXP_DATE, RGT_DTTM
FROM T_TOKEN_ACCESS
WHERE
	TOKEN = #{value	, jdbcType=VARCHAR};

/* com.erns.coching.login.mapper.BlacklistTokenDAO.insertFromRefresh */

DELETE FROM T_TOKEN_BLACKLIST WHERE TOKEN = #{value	, jdbcType=VARCHAR};


INSERT INTO T_TOKEN_BLACKLIST (
	TOKEN, SITE_TYPE, MEMB_SEQ, EXP_DATE, RGT_DTTM
)
SELECT
	TOKEN, SITE_TYPE, MEMB_SEQ, EXP_DATE, RGT_DTTM
FROM T_TOKEN_REFRESH
